#include <stdio.h>
#include <inttypes.h>
int main(){
    unsigned long long T; if(scanf("%llu", &T)!=1) return 0;
    while(T--){
        unsigned long long N, K; scanf("%llu %llu", &N, &K);
        unsigned long long per = 0, left = N;
        if(K!=0 && N>=K){
            per = N / K;
            left = N % K;
        }
        printf("%llu %llu\n", per, left);
    }
    return 0;
}

